export const BOOKS: Book[] = [
  { id: 1, rank: 1, title: "The Road", author: "Cormac McCarthy", year: 2006, genre: "Literary Fiction", coverId: 198120,
    description: "A father and his young son journey across a post-apocalyptic American landscape, struggling to survive and maintain their humanity. Spare and devastating, it is a meditation on love and the will to endure.",
    longDescription: "A father and his young son journey across a post-apocalyptic American landscape, struggling to survive and maintain their humanity. McCarthy strips his prose down to its barest bones — no quotation marks, almost no proper nouns — to create a world emptied of everything but the bond between parent and child. The novel's power comes not from plot but from the relentless accumulation of small acts of love and survival in the face of absolute desolation. Winner of the Pulitzer Prize, it is widely considered one of the most affecting novels of the 21st century." },

  { id: 2, rank: 2, title: "Wolf Hall", author: "Hilary Mantel", year: 2009, genre: "Historical Fiction", coverId: 8345848,
    description: "Thomas Cromwell rises from humble origins to become Henry VIII's chief minister in Tudor England. Mantel's intimate, present-tense narration transforms a well-known history into something entirely fresh.",
    longDescription: "Thomas Cromwell rises from humble origins — the son of a blacksmith — to become Henry VIII's chief minister in Tudor England. Mantel's intimate, present-tense narration places us inside Cromwell's watchful, calculating mind as he navigates a court of constant danger and shifting alliances. The novel transforms familiar history into something startlingly immediate, making Cromwell one of the most fully realized characters in contemporary fiction. Winner of the Man Booker Prize, it launched one of the most acclaimed trilogies in modern literature." },

  { id: 3, rank: 3, title: "Lincoln in the Bardo", author: "George Saunders", year: 2017, genre: "Literary Fiction", coverId: 7909378,
    description: "On the night of his son Willie's death, President Lincoln visits the crypt—while the boy's spirit lingers among a chorus of ghosts in a Georgetown cemetery. An experimental masterpiece of grief and American history.",
    longDescription: "On the night of his son Willie's death, President Lincoln visits the crypt — while the boy's spirit lingers among a chorus of ghosts in a Georgetown cemetery. Saunders constructs the novel from hundreds of voices: fictional ghosts, each trapped by their own unfinished business, intercut with excerpts from real historical accounts of Lincoln's grief. The result is a dazzlingly original meditation on loss, the nature of the afterlife, and the cost of the Civil War. Winner of the Man Booker Prize, it announced Saunders as one of the most inventive novelists of his generation." },

  { id: 4, rank: 4, title: "A Little Life", author: "Hanya Yanagihara", year: 2015, genre: "Literary Fiction", coverId: 12065783,
    description: "Four college friends navigate adult life in New York City over decades, as the haunted past of one of them—Jude St. Francis—slowly comes to light. An emotionally overwhelming saga of trauma, friendship, and survival.",
    longDescription: "Four college friends navigate adult life in New York City over decades, as the haunted past of one of them — Jude St. Francis — slowly comes to light. Yanagihara is unflinching in her depiction of childhood abuse and its long aftermath, but equally precise about the redemptive power of friendship and chosen family. The novel is deliberately operatic in its emotional scale, demanding total commitment from the reader and rewarding it with one of the most intense reading experiences in recent memory. A finalist for the Man Booker Prize and the National Book Award." },

  { id: 5, rank: 5, title: "The Underground Railroad", author: "Colson Whitehead", year: 2016, genre: "Historical Fiction", coverId: 7899016,
    description: "A young enslaved woman named Cora escapes a Georgia plantation and discovers that the Underground Railroad is literally a network of secret tunnels and trains. A Pulitzer Prize-winning reimagining of American history.",
    longDescription: "A young enslaved woman named Cora escapes a Georgia plantation and discovers that the Underground Railroad is literally a network of secret tunnels and trains running beneath the South. Each state Cora passes through reimagines a different aspect of American racial history — eugenics, segregation, assimilation — as if filtered through a dark alternate timeline. Whitehead's approach makes the horror of slavery feel both historically grounded and freshly shocking, refusing to let the distance of history provide comfort. Winner of the Pulitzer Prize and the National Book Award." },

  { id: 6, rank: 6, title: "Gilead", author: "Marilynne Robinson", year: 2004, genre: "Literary Fiction", coverId: 1472533,
    description: "An elderly Congregationalist minister in Iowa writes a long letter to his young son, knowing he will not live to see the boy grow up. A Pulitzer Prize-winner suffused with theological depth and quiet beauty.",
    longDescription: "An elderly Congregationalist minister in Gilead, Iowa writes a long letter to his young son, knowing he will not live to see the boy grow up. John Ames's letter is a meditation on faith, memory, and what it means to have lived well — suffused with a stillness and gravity that sets it apart from almost any other American novel of the era. Robinson writes theology as lyric poetry, finding transcendence in the ordinary details of a small life. Winner of the Pulitzer Prize, the first in a beloved cycle of novels set in the same Iowa town." },

  { id: 7, rank: 7, title: "Never Let Me Go", author: "Kazuo Ishiguro", year: 2005, genre: "Science Fiction", coverId: 1047334,
    description: "Three friends who grew up together at an idyllic English boarding school slowly uncover the disturbing truth about their purpose in life. A haunting meditation on mortality, memory, and what it means to be human.",
    longDescription: "Three friends who grew up together at an idyllic English boarding school slowly uncover the disturbing truth about their purpose in life. Ishiguro withholds the central revelation with extraordinary craft, letting it emerge gradually through the narrator Kathy's quietly devastating reminiscences. The horror of the novel lies not in dramatic confrontation but in the characters' resigned acceptance of their fate — a passivity that raises profound questions about free will and the stories we tell ourselves. A masterwork of restraint from the 2017 Nobel laureate." },

  { id: 8, rank: 8, title: "The Corrections", author: "Jonathan Franzen", year: 2001, genre: "Literary Fiction", coverId: 9273701,
    description: "The three adult children of an elderly Midwestern couple struggle with their own fractured lives while their parents' world slowly comes apart. A sprawling, savagely funny portrait of a contemporary American family.",
    longDescription: "The three adult children of an elderly Midwestern couple — Alfred and Enid Lambert — struggle with their own fractured lives while their parents' world slowly comes apart. Franzen renders each sibling's particular failure with merciless precision: the academic, the financier, the chef, each running from the family they can never fully escape. The novel is both a scathing satire of American consumer culture and a deeply felt portrait of a family trying to hold on. Winner of the National Book Award, it established Franzen as one of the defining novelists of his era." },

  { id: 9, rank: 9, title: "The Brief Wondrous Life of Oscar Wao", author: "Junot Díaz", year: 2007, genre: "Literary Fiction", coverId: 12451659,
    description: "Oscar de León, an overweight Dominican-American nerd obsessed with fantasy novels, searches for love while his family contends with the legacy of Trujillo's dictatorship. A Pulitzer Prize-winning fusion of genre and literary fiction.",
    longDescription: "Oscar de León, an overweight Dominican-American nerd obsessed with fantasy novels and role-playing games, searches hopelessly for love while his family contends with the fukú — a curse that has haunted them since the era of Trujillo's dictatorship. Díaz writes in a voice that blends street slang, literary allusion, and footnotes of brutal Dominican history, creating something entirely new. The novel is simultaneously a love letter to genre fiction, a history of political terror, and a meditation on what it means to grow up between cultures. Winner of the Pulitzer Prize." },

  { id: 10, rank: 10, title: "Americanah", author: "Chimamanda Ngozi Adichie", year: 2013, genre: "Literary Fiction", coverId: 8474037,
    description: "Ifemelu leaves Nigeria for America and Obinze goes to England, and years later they reconnect in Lagos having both changed profoundly. A brilliant, witty examination of race, identity, and belonging across continents.",
    longDescription: "Ifemelu leaves Nigeria for America to study, while her first love Obinze attempts to make his way in England without papers, and years later they reconnect in Lagos having both changed profoundly. Adichie uses Ifemelu's popular blog about race in America as a structural device, embedding sharp, funny observations about how race is performed and perceived differently in America than anywhere else. The novel is at once a love story, an immigrant story, and one of the most incisive accounts of what it means to be Black in America written by an outsider. Longlisted for the Man Booker Prize." },

  { id: 11, rank: 11, title: "White Teeth", author: "Zadie Smith", year: 2000, genre: "Literary Fiction", coverId: 5276331,
    description: "Two wartime friends—an Englishman and a Bangladeshi—reunite decades later in North London as their families become entangled across cultures and generations. A dazzling debut exploring identity, history, and multiculturalism.",
    longDescription: "Two wartime friends — an Englishman named Archie Jones and a Bangladeshi named Samad Iqbal — reunite decades later in North London as their families become entangled across cultures and generations. Smith writes with extraordinary wit and energy, juggling multiple timelines and a vast cast of characters to produce an exuberant portrait of multicultural Britain at the turn of the millennium. The novel is sprawling by design, mirroring the chaos and possibility of a society in the midst of demographic transformation. Published when Smith was just 24, it announced one of the most vital voices in contemporary fiction." },

  { id: 12, rank: 12, title: "Normal People", author: "Sally Rooney", year: 2018, genre: "Literary Fiction", coverId: 8794265,
    description: "Connell and Marianne grow up in the same small Irish town but move in different social circles, and their relationship shifts dramatically as they attend university together. A precise, psychologically astute novel about power, intimacy, and class.",
    longDescription: "Connell and Marianne grow up in the same small Irish town but move in entirely different social circles — he is popular, she is isolated — and their secret relationship sets off years of longing, estrangement, and reunion. Rooney writes dialogue without quotation marks and tracks the internal lives of her characters with surgical precision, making visible the tiny power shifts and misunderstandings that shape intimacy. The novel is also quietly a story about class in Ireland — how it shapes aspiration, self-presentation, and the ability to be known. A global phenomenon that made Rooney one of the defining writers of her generation." },

  { id: 13, rank: 13, title: "Exit West", author: "Mohsin Hamid", year: 2017, genre: "Literary Fiction", coverId: 7909066,
    description: "In an unnamed city on the brink of civil war, two young people fall in love and eventually flee through mysterious doors that transport migrants to different corners of the world. A fable about displacement and the possibility of belonging.",
    longDescription: "In an unnamed city on the brink of civil war, two young people — Saeed and Nadia — fall in love and must eventually flee through mysterious doors that transport migrants to different corners of the world. Hamid's magical doors literalize the experience of migration, stripping away the logistics to focus on the emotional reality of displacement: the grief of leaving, the difficulty of arrival, the way relationships are tested by upheaval. The novel is a fable about our time, written in a spare, hypnotic prose that gives even mundane moments a mythic weight. Shortlisted for the Man Booker Prize." },

  { id: 14, rank: 14, title: "The Sympathizer", author: "Viet Thanh Nguyen", year: 2015, genre: "Literary Fiction", coverId: 7913176,
    description: "A communist spy working for the South Vietnamese army flees to America after the fall of Saigon, continuing his double life in exile. A Pulitzer Prize-winner that examines the Vietnam War from the other side with dark humor.",
    longDescription: "A communist spy working for the South Vietnamese army flees to America after the fall of Saigon, continuing his double life in exile while writing a forced confession to his communist superiors. Nguyen's narrator is a man of two minds and two loyalties — literally: he is the bastard son of a French priest and a Vietnamese woman — and his divided consciousness becomes the novel's central metaphor. The book is a scathing, darkly comic critique of both Vietnamese communism and American imperialism, insisting that every side in war is morally compromised. Winner of the Pulitzer Prize." },

  { id: 15, rank: 15, title: "Olive Kitteridge", author: "Elizabeth Strout", year: 2008, genre: "Literary Fiction", coverId: 2733808,
    description: "Thirteen linked stories revolve around the sharp, difficult, perceptive retired schoolteacher Olive Kitteridge in a small Maine coastal town. A Pulitzer Prize-winning portrait of ordinary life's hidden pain and unexpected grace.",
    longDescription: "Thirteen linked stories revolve around Olive Kitteridge — a sharp, difficult, perceptive retired schoolteacher — in the small Maine coastal town of Crosby. Strout gives Olive a supporting role in many of the stories, allowing us to see her as others do before we understand her from the inside, a structural choice that slowly builds a portrait of tremendous complexity. The novel is about the damage parents do to children, the loneliness of long marriages, and the way small communities both sustain and suffocate. Winner of the Pulitzer Prize, it spawned a beloved HBO miniseries and a sequel." },

  { id: 16, rank: 16, title: "Between the World and Me", author: "Ta-Nehisi Coates", year: 2015, genre: "Nonfiction", coverId: 11328078,
    description: "Written as a letter to his teenage son, Coates meditates on the history of racial violence in America and the vulnerability of Black bodies. A searing, essential work that reframes American history through lived experience.",
    longDescription: "Written as a letter to his teenage son Samori, Coates meditates on the history of racial violence in America and the particular vulnerability of the Black body as a site of plunder and terror. Drawing on his own experiences growing up in Baltimore, his time at Howard University, and the murder of his friend Prince Jones by a police officer, Coates constructs a vision of America that refuses consolation. The book owes a debt to James Baldwin's 'The Fire Next Time' in both form and urgency, and was immediately recognized as a defining document of its moment. Winner of the National Book Award." },

  { id: 17, rank: 17, title: "Cloud Atlas", author: "David Mitchell", year: 2004, genre: "Science Fiction", coverId: 6714077,
    description: "Six interlocking narratives span centuries—from the South Pacific in 1850 to a post-apocalyptic future—each nested within the next like Russian dolls. A breathtakingly ambitious novel about the interconnectedness of souls across time.",
    longDescription: "Six interlocking narratives span centuries — from a 19th-century sea voyage in the South Pacific to a far-future post-apocalyptic Hawaii — each nested within the next like Russian dolls, and each written in a completely different style and register. Mitchell's conceit is that a single soul transmigrates through history, always struggling against the powerful and oppressive, always seeking connection. The novel is an audacious formal experiment that rewards patience: each half-story withheld in the first half is completed in reverse order in the second. A Reader's Companion to the Booker Prize shortlist and one of the most discussed novels of the decade." },

  { id: 18, rank: 18, title: "The Vegetarian", author: "Han Kang", year: 2007, genre: "Literary Fiction", coverId: 15182525,
    description: "After a disturbing dream, a seemingly ordinary Korean woman stops eating meat, setting off a chain of increasingly violent events within her family. A surreal, unsettling exploration of conformity, female autonomy, and bodily desire.",
    longDescription: "After a deeply disturbing dream, Yeong-hye — a seemingly ordinary Korean housewife — stops eating meat and refuses to resume, setting off a chain of increasingly violent events within her family. Told in three parts from three different perspectives, the novel charts Yeong-hye's transformation from passive wife to something more like a plant — a radical act of self-erasure that reads simultaneously as madness and liberation. Han Kang writes the body with an intensity that is almost physical, exploring what happens when a woman refuses to perform the social roles assigned to her. Winner of the International Booker Prize." },

  { id: 19, rank: 19, title: "Middlesex", author: "Jeffrey Eugenides", year: 2002, genre: "Literary Fiction", coverId: 12367196,
    description: "Cal Stephanides traces his family's history from a small village in Greece through Prohibition-era Detroit to suburban Michigan, uncovering the genetic secret of his intersex condition. A Pulitzer Prize-winning multigenerational epic.",
    longDescription: "Cal Stephanides narrates the multigenerational story of his Greek-American family — from a village on the slopes of Mount Olympus to Prohibition-era Detroit to the suburbs of Grosse Pointe — in order to uncover the genetic secret behind his own intersex condition. Eugenides moves between the sweeping and the intimate with remarkable ease, conducting research into genetics and Greek history while also writing a deeply personal coming-of-age story. The novel celebrates the immigrant experience while also examining the sometimes brutal enforcement of gender norms. Winner of the Pulitzer Prize." },

  { id: 20, rank: 20, title: "Atonement", author: "Ian McEwan", year: 2001, genre: "Literary Fiction", coverId: 8381043,
    description: "A precocious thirteen-year-old misidentifies a crime on a hot English summer evening in 1935, and the consequences ripple across decades of war and separation. A dazzling examination of guilt, memory, and the power of fiction.",
    longDescription: "A precocious thirteen-year-old named Briony Tallis misidentifies a crime on a sweltering English summer evening in 1935, and the consequences of her testimony ripple across decades of war, separation, and irreversible loss. McEwan structures the novel in three distinct registers — the lush, claustrophobic prewar country house; the brutal chaos of Dunkirk; the long aftermath — before a final metafictional twist reframes everything we have read. The novel is ultimately a meditation on the power and limits of fiction itself, and on whether art can offer any real form of atonement. Shortlisted for the Man Booker Prize and the Whitbread Novel Award." },

  { id: 21, rank: 21, title: "The Amazing Adventures of Kavalier and Clay", author: "Michael Chabon", year: 2000, genre: "Literary Fiction", coverId: null,
    description: "Two cousins—a Czech refugee and a Brooklyn dreamer—create a comic-book superhero during the Golden Age of comics and WWII. A Pulitzer Prize-winning celebration of escapism, art, and the immigrant experience.",
    longDescription: "Joe Kavalier, a Czech refugee who has escaped Nazi-occupied Prague, arrives in Brooklyn and teams up with his cousin Sammy Clay to create a comic-book superhero called The Escapist. Set against the Golden Age of comics and World War II, the novel traces their creative partnership, their loves and losses, and Joe's obsessive quest to rescue his family from Europe. Chabon writes about comics with genuine love and expertise, treating the medium as a legitimate art form and a vehicle for working through the horrors of the 20th century. Winner of the Pulitzer Prize." },

  { id: 22, rank: 22, title: "Life of Pi", author: "Yann Martel", year: 2001, genre: "Literary Fiction", coverId: 12840573,
    description: "After a shipwreck, a sixteen-year-old Indian boy finds himself adrift in the Pacific Ocean on a lifeboat with a Bengal tiger. This Booker Prize-winning novel is a story about the power of storytelling and faith.",
    longDescription: "After a shipwreck, Pi Patel — a sixteen-year-old Indian boy who practices Hinduism, Christianity, and Islam simultaneously — finds himself adrift in the Pacific Ocean on a lifeboat with a 450-pound Bengal tiger named Richard Parker. The survival story that follows is gripping on its own terms, but the novel's ambition is larger: Pi's narrative eventually offers an alternative version of events, and the question of which story is 'true' becomes the book's central philosophical puzzle. Martel argues that the best story — the one that gives meaning to suffering — is the one worth believing. Winner of the Man Booker Prize." },

  { id: 23, rank: 23, title: "Pachinko", author: "Min Jin Lee", year: 2017, genre: "Historical Fiction", coverId: 8044605,
    description: "Four generations of a Korean family navigate discrimination and hardship in Japan, from colonial-era Korea to 1980s Osaka. An epic saga of sacrifice, identity, and the stubborn persistence of hope.",
    longDescription: "Four generations of a Korean family — beginning with a young woman's illicit pregnancy in colonial-era Korea — navigate discrimination, poverty, and the complex question of identity as ethnic Koreans living in Japan. Lee spent decades researching the Zainichi Korean community and the novel has the weight of that scholarship, but it reads above all as a saga of ordinary people making extraordinary sacrifices for their descendants. The title refers to the pachinko parlor business that sustains one branch of the family, a metaphor for the rigged game of life that immigrants must play. A National Book Award finalist." },

  { id: 24, rank: 24, title: "Station Eleven", author: "Emily St. John Mandel", year: 2014, genre: "Science Fiction", coverId: 7369961,
    description: "A traveling Shakespearean theater company performs for survivors in the Great Lakes region twenty years after a flu pandemic wipes out most of civilization. A lyrical meditation on art, memory, and what makes life worth living.",
    longDescription: "A traveling Shakespearean theater company performs for survivors scattered across the Great Lakes region twenty years after the Georgian Flu pandemic wipes out most of civilization. Mandel weaves together timelines before and after the collapse, centering on a famous actor who dies of a heart attack on stage the night the pandemic begins. The novel is unusual in the post-apocalyptic genre for its warmth and its insistence on beauty — on the arts as essential rather than frivolous. Its motto, 'survival is insufficient,' captures something true about what makes human life worth living. A National Book Award finalist." },

  { id: 25, rank: 25, title: "The Sellout", author: "Paul Beatty", year: 2015, genre: "Literary Fiction", coverId: 7897222,
    description: "A young Black man from a tiny community in Los Angeles reinstates slavery and segregation in his hometown, eventually ending up before the Supreme Court. The first American novel to win the Booker Prize—outrageous, hilarious, and bracingly sharp.",
    longDescription: "A young Black man from a tiny, officially nonexistent community on the outskirts of Los Angeles reinstates slavery and re-segregates the local school in an attempt to restore his hometown's sense of identity, eventually ending up before the Supreme Court. Beatty's satire is savage and relentless, targeting American racial liberalism and the mythology of progress with equal fury. The comedy is so dense and so fast — riffing on everything from social science to blaxploitation films — that it demands re-reading. The first American novel to win the Man Booker Prize." },

  { id: 26, rank: 26, title: "Jonathan Strange and Mr Norrell", author: "Susanna Clarke", year: 2004, genre: "Fantasy", coverId: 525391,
    description: "In an alternate 19th-century England where magic was once widespread, two very different magicians attempt to restore English magic. A massively inventive debut written in the style of a Victorian novel, complete with footnotes.",
    longDescription: "In an alternate 19th-century England where magic was once widespread but has long since become theoretical, two very different magicians — the reclusive, scholarly Mr. Norrell and the dashing, instinctive Jonathan Strange — attempt to restore English magic, with consequences neither can foresee. Clarke spent a decade writing the novel in the style of a Victorian triple-decker, complete with footnotes referencing an entire invented body of magical history. The world she creates is peculiar and compelling, rooted in English folklore while feeling absolutely unlike any other fantasy. A massive critical and commercial success on publication." },

  { id: 27, rank: 27, title: "The Known World", author: "Edward P. Jones", year: 2003, genre: "Historical Fiction", coverId: 34376,
    description: "A formerly enslaved man in antebellum Virginia becomes a slaveholder himself, and the novel explores the moral complexities of his world after his death. A Pulitzer Prize-winning examination of power and complicity in the antebellum South.",
    longDescription: "Henry Townsend, a formerly enslaved man in antebellum Virginia who has been freed by his owner, becomes a slaveholder himself — and the novel explores the moral complexities of his world after his early death, as his plantation falls into chaos. Jones writes with a god-like narrator who moves freely through time, revealing fates and connections that his characters cannot see, giving the novel an almost Biblical quality. The central provocation — that Black slaveholders existed, and participated in the same moral corruption as white ones — is handled without simplification. Winner of the Pulitzer Prize and the National Book Critics Circle Award." },

  { id: 28, rank: 28, title: "A Visit from the Goon Squad", author: "Jennifer Egan", year: 2010, genre: "Literary Fiction", coverId: 6452334,
    description: "Interconnected stories about a music executive and his young assistant circle around themes of time, technology, and the ways people change over decades. A Pulitzer Prize-winning novel-in-stories that includes a chapter told in PowerPoint.",
    longDescription: "Interconnected stories orbit around Bennie Salazar, a music executive, and Sasha, his young kleptomaniac assistant, weaving between New York, San Francisco, Naples, and Africa across several decades. Egan experiments aggressively with form — one chapter is entirely in second-person, another is a PowerPoint presentation of a teenage girl's diary — exploring how new technologies shape intimacy and memory. The novel's great subject is time: the goon squad of the title, and the way it transforms everyone. Winner of the Pulitzer Prize and the National Book Critics Circle Award." },

  { id: 29, rank: 29, title: "My Brilliant Friend", author: "Elena Ferrante", year: 2011, genre: "Literary Fiction", coverId: 13772133,
    description: "Elena and Lila grow up together in a poor, violent neighborhood in postwar Naples, their intense friendship shaping both their lives as they come of age. The first of the Neapolitan Novels and a profound study of female ambition and friendship.",
    longDescription: "Elena Greco and Lila Cerullo grow up together in a poor, violent neighborhood in postwar Naples, their intense and competitive friendship the defining relationship of both their lives. Ferrante — writing under a pseudonym whose identity remains unknown — brings an almost documentary realism to the neighborhood and its people, while also writing about female interiority with a frankness rarely seen. The first of four Neapolitan Novels, it covers their childhood and early adolescence, establishing the push-pull dynamic that will define the entire series. One of the most discussed literary phenomena of the 2010s." },

  { id: 30, rank: 30, title: "The Goldfinch", author: "Donna Tartt", year: 2013, genre: "Literary Fiction", coverId: 8771366,
    description: "Theo Decker survives a bombing at a New York museum that kills his mother, and spends the next years in the underworld of antique furniture dealing, clutching a small Dutch masterpiece. A Pulitzer Prize-winning Dickensian saga.",
    longDescription: "Thirteen-year-old Theo Decker survives a bombing at a New York art museum that kills his mother, and in the chaos flees with a small Dutch masterpiece — Fabritius's 'The Goldfinch' — that becomes both his talisman and his burden across years of homelessness, drug addiction, and the Manhattan antique furniture trade. Tartt writes in the tradition of Dickens, giving her novel the sweep and moral seriousness of the 19th-century novel while setting it firmly in contemporary New York and Amsterdam. The painting serves as a meditation on art's capacity to outlast the destruction that surrounds it. Winner of the Pulitzer Prize." },

  { id: 31, rank: 31, title: "Tenth of December", author: "George Saunders", year: 2013, genre: "Short Stories", coverId: 8346437,
    description: "Eleven stories ranging from corporate dystopia to small-town heartbreak, all infused with Saunders's characteristic blend of dark comedy and deep empathy. The book that cemented his reputation as one of America's greatest short story writers.",
    longDescription: "Eleven stories ranging from near-future corporate dystopia to small-town Midwestern heartbreak, all infused with Saunders's characteristic blend of dark comedy, formal inventiveness, and deep human empathy. Saunders writes working-class and lower-middle-class America with genuine love and without condescension, finding the tragic absurdity in ordinary lives caught in systems designed to grind them down. The title story, about an elderly man attempting suicide and a lonely adolescent boy who accidentally intersects with him, may be the finest short story written in English in the 21st century. Won the Folio Prize." },

  { id: 32, rank: 32, title: "H Is for Hawk", author: "Helen Macdonald", year: 2014, genre: "Memoir", coverId: 917578,
    description: "After her father's sudden death, the author decides to train a goshawk—one of the most difficult birds in falconry—as a way of processing her grief. An extraordinary memoir that weaves together nature writing, biography, and bereavement.",
    longDescription: "After the sudden death of her father, Macdonald — a falconer and naturalist — decides to train a goshawk, one of the most formidably difficult birds in falconry, as a way of losing herself in an obsessive physical task. The memoir interweaves her own experience with the life of T.H. White, who also trained a goshawk and wrote about it in 'The Goshawk,' building a meditation on grief, wildness, and the human need to find kinship with the natural world. Macdonald writes about hawks and falconry with expert precision, but the book's real subject is what happens when we use animals to avoid confronting our own grief. Winner of the Samuel Johnson Prize and the Costa Book Award." },

  { id: 33, rank: 33, title: "Educated", author: "Tara Westover", year: 2018, genre: "Memoir", coverId: 8314077,
    description: "Growing up in the mountains of Idaho in a survivalist family, the author had no birth certificate and never attended school, yet eventually earned a PhD from Cambridge. A gripping account of education, family, and self-invention.",
    longDescription: "Tara Westover grew up in the mountains of Idaho in a survivalist, anti-government family: no birth certificate, no school, working in her father's junkyard and her brother's crew, and not visiting a doctor even for serious injuries. Through a combination of autodidactic reading and sheer determination, she eventually enrolled at Brigham Young University and went on to earn a PhD from Cambridge. The memoir is both a gripping personal narrative and a profound meditation on what education actually is — the painful process of constructing a self separate from the family you love. A #1 New York Times bestseller for years." },

  { id: 34, rank: 34, title: "The Year of Magical Thinking", author: "Joan Didion", year: 2005, genre: "Memoir", coverId: 13693,
    description: "Written in the year following the sudden death of her husband John Gregory Dunne, Didion examines grief with the precision and clarity that define her work. A National Book Award-winning masterpiece about loss and the rituals of mourning.",
    longDescription: "Written in the year following the sudden death of her husband John Gregory Dunne — who died of a heart attack while they were eating dinner — Didion examines grief with the precision and analytical detachment that define all her work, even as she acknowledges that grief defeats analysis. The 'magical thinking' of the title refers to the irrational beliefs the grieving mind constructs: that if she kept his shoes, he could not be dead; that there would be a phone call. Didion treats her own shock and dysfunction not as weakness but as data, producing a grief memoir unlike any other. Winner of the National Book Award." },

  { id: 35, rank: 35, title: "Just Kids", author: "Patti Smith", year: 2010, genre: "Memoir", coverId: 6671097,
    description: "The legendary singer-songwriter recounts her youth in New York City in the late 1960s and her transformative friendship with the photographer Robert Mapplethorpe. A National Book Award-winning portrait of artistic coming-of-age.",
    longDescription: "Patti Smith recounts her arrival in New York City at nineteen, penniless and in love with art, and the transformative friendship she formed with Robert Mapplethorpe — a relationship that was romantic, artistic, and finally, as Mapplethorpe's fame grew and he moved into the gay world, a love that reshaped itself into something else. The memoir captures a lost New York — the Chelsea Hotel, Max's Kansas City, the fertile chaos of the late-1960s and 1970s downtown scene — with a poet's eye and a grieving friend's devotion. Completed after Mapplethorpe's death from AIDS. Winner of the National Book Award." },

  { id: 36, rank: 36, title: "The Warmth of Other Suns", author: "Isabel Wilkerson", year: 2010, genre: "Nonfiction", coverId: 10129368,
    description: "Through three unforgettable characters, Wilkerson chronicles the Great Migration of African Americans from the South to the North from 1915 to 1970. A monumental work of narrative history that reads like a novel.",
    longDescription: "Through three unforgettable individuals — Ida Mae Gladney, George Starling, and Robert Foster — Wilkerson chronicles the Great Migration, in which six million African Americans left the Jim Crow South for the cities of the North and West between 1915 and 1970. Wilkerson spent fifteen years on the project, conducting over a thousand interviews, and her reporting grounds the history in specific, vividly rendered lives. The result is both rigorously researched and completely readable — a work that treats migration as the defining event in 20th-century African American history, and makes that claim feel earned. Winner of the National Book Critics Circle Award." },

  { id: 37, rank: 37, title: "When Breath Becomes Air", author: "Paul Kalanithi", year: 2016, genre: "Memoir", coverId: 11463139,
    description: "A brilliant neurosurgeon confronts his own mortality after being diagnosed with terminal lung cancer and writes about his transformation from doctor to patient. A stunning meditation on what makes a life worth living.",
    longDescription: "Paul Kalanithi was completing his neurosurgery residency at Stanford — one of the most demanding training programs in medicine — when he was diagnosed with stage IV lung cancer at 36. The memoir he wrote in the time remaining explores the question that had drawn him to both literature and medicine: what makes a life worth living, and what remains worth living for when the future collapses? Kalanithi writes with the precision of a physician and the soul of a humanist, finding meaning in work even as his body fails. He died in 2015, eight months before publication, and the book was completed with a coda by his wife. A #1 New York Times bestseller." },

  { id: 38, rank: 38, title: "Salvage the Bones", author: "Jesmyn Ward", year: 2011, genre: "Literary Fiction", coverId: 6906262,
    description: "During the twelve days before Hurricane Katrina, a poor Black family in rural Mississippi fights to survive amid poverty, and a teenage girl tries to protect the secret of her pregnancy. A National Book Award-winning novel of extraordinary power.",
    longDescription: "During the twelve days before Hurricane Katrina makes landfall, the Batiste family — a widowed father and his four children — scrapes along in rural Mississippi, and fifteen-year-old Esch tries to protect the secret of her pregnancy. Ward writes poverty and the Gulf Coast landscape with extraordinary specificity, and the hurricane's arrival is rendered with a power that is almost overwhelming. The novel draws on Greek mythology — Esch is reading Edith Hamilton and identifies with Medea — elevating its story of a poor Black family to the scale of tragedy. Winner of the National Book Award." },

  { id: 39, rank: 39, title: "The Nickel Boys", author: "Colson Whitehead", year: 2019, genre: "Historical Fiction", coverId: 8747820,
    description: "Two boys at a reform school in Jim Crow-era Florida form a friendship that must carry them through years of brutal abuse. A second Pulitzer Prize for Whitehead, a searing indictment of institutional cruelty.",
    longDescription: "Elwood Curtis, a Black teenager with a bright future who idolizes Martin Luther King Jr., is falsely accused of a crime and sent to the Nickel Academy — a reform school in Jim Crow-era Florida modeled on the real Dozier School for Boys, where abuse and murder were endemic. There he meets Turner, a more cynical boy, and their friendship becomes the moral center of the novel. Whitehead tells the story with a controlled restraint that makes the violence more rather than less devastating, and a structural twist at the end reframes everything. Winner of a second Pulitzer Prize, making Whitehead one of only three novelists to win the award twice." },

  { id: 40, rank: 40, title: "Half of a Yellow Sun", author: "Chimamanda Ngozi Adichie", year: 2006, genre: "Historical Fiction", coverId: 8472660,
    description: "Set during the Biafran War in 1960s Nigeria, the novel follows three characters as war tears apart their lives and relationships. A harrowing, intimate portrait of political violence and its human cost.",
    longDescription: "Set during the Biafran War in 1960s Nigeria, the novel follows three characters — twin sisters from an Igbo intellectual family, and Richard, a young Englishman — as the war tears apart their lives and forces impossible choices. Adichie grew up hearing family stories about the war, in which over a million people died, and she writes with the authority of inherited memory alongside historical research. The novel refuses easy political judgment: it is fierce in its portrayal of Nigerian nationalist politics while also depicting the ordinary human cost of the conflict. Winner of the Orange Prize for Fiction." },

  { id: 41, rank: 41, title: "Cutting for Stone", author: "Abraham Verghese", year: 2009, genre: "Literary Fiction", coverId: 8474220,
    description: "Twin boys born in a mission hospital in Addis Ababa grow up to become doctors, their lives shaped by the mysterious circumstances of their birth. A sweeping saga of medicine, family, and exile spanning three continents.",
    longDescription: "Marion and Shiva Stone are born conjoined at the head in a mission hospital in Addis Ababa, the product of a forbidden union between an Indian nun and a British surgeon. Their lives are shaped by the circumstances of their birth — their mother's death, their father's flight, and the devotion of the Ethiopian doctors who raise them. Verghese, himself a physician, writes about medicine with deep knowledge and genuine passion, and the novel is as much a tribute to doctoring as it is a family saga. The story moves from Ethiopia to New York, spanning the political upheavals of both continents." },

  { id: 42, rank: 42, title: "The Tiger's Wife", author: "Téa Obreht", year: 2011, genre: "Literary Fiction", coverId: 6684589,
    description: "A young doctor investigates the stories surrounding her grandfather's life and death in a fictional Balkan country, uncovering myths woven into history. An atmospheric debut that blends war narrative with folk legend.",
    longDescription: "Natalia, a young doctor, travels across a fictional Balkan country to investigate the strange circumstances of her grandfather's death, uncovering two mythic stories that have shaped his life: his childhood encounter with a tiger's wife, and his relationship with a deathless man. Obreht weaves Balkan folklore and the trauma of the region's wars into a narrative of extraordinary atmospheric density. The novel is fascinated by the stories people tell to survive catastrophe — how myth and magic become necessary coping mechanisms when history becomes too brutal to face directly. Winner of the Orange Prize for Fiction at age 26." },

  { id: 43, rank: 43, title: "The Book Thief", author: "Markus Zusak", year: 2005, genre: "Historical Fiction", coverId: 8153054,
    description: "Narrated by Death, the story follows Liesel Meminger, a young girl living with a foster family in Nazi Germany who steals books and shares them with others. A beloved novel about the life-sustaining power of words.",
    longDescription: "Narrated by Death — who speaks about the souls he collects with weary compassion — the story follows Liesel Meminger, a young German girl sent to live with a foster family in a working-class Munich suburb during World War II. Liesel begins stealing books and sharing them, first with her foster father and eventually with the Jewish man hiding in their basement. Zusak's conceit of Death as narrator gives the novel an unusual tenderness, investing even the most ordinary moments with the knowledge of what is coming. Originally published as a young-adult novel, it has since been embraced as a work for all ages." },

  { id: 44, rank: 44, title: "The Curious Incident of the Dog in the Night-Time", author: "Mark Haddon", year: 2003, genre: "Literary Fiction", coverId: 7890719,
    description: "Christopher, a fifteen-year-old with behavioral differences, investigates the murder of a neighbor's dog and inadvertently uncovers startling family secrets. A uniquely voiced, deeply affecting mystery told from the inside of an extraordinary mind.",
    longDescription: "Christopher Boone — fifteen years old, mathematically gifted, and behaviorally different in ways the novel never names — decides to investigate the murder of his neighbor's dog and inadvertently uncovers family secrets that overturn his world. Haddon writes entirely in Christopher's voice, and the formal constraints this imposes — literal thinking, aversion to metaphor, meticulous logic — create a perspective that is both deeply limiting and strangely illuminating. The novel won both the Whitbread Novel Award and the Whitbread Book of the Year, a rare double, and became a celebrated stage adaptation." },

  { id: 45, rank: 45, title: "Everything Is Illuminated", author: "Jonathan Safran Foer", year: 2002, genre: "Literary Fiction", coverId: 27640,
    description: "A young American Jew travels to Ukraine to find the woman who saved his grandfather from the Nazis, guided by a young Ukrainian and his grandfather. A formally inventive debut that weaves comedy and tragedy around the Holocaust.",
    longDescription: "A young American named Jonathan Safran Foer travels to Ukraine to find the woman who saved his grandfather from the Nazis, guided by a young Ukrainian named Alex and his grandfather, who claims to be blind but is not. Foer structures the novel in three strands: Alex's hilariously malapropistic account of their journey, Jonathan's magical-realist history of the shtetl of Trachimbrod, and the letters Alex writes to Jonathan after the trip — each illuminating the others. The novel is both very funny and very sad, insisting that the Holocaust can only be approached obliquely, through the distortions of fiction and fable." },

  { id: 46, rank: 46, title: "The Kite Runner", author: "Khaled Hosseini", year: 2003, genre: "Literary Fiction", coverId: 14846827,
    description: "In Afghanistan, a privileged boy betrays his servant's son, and spends the rest of his life seeking redemption. A devastating debut novel about guilt, forgiveness, and the power of friendship across class divides.",
    longDescription: "Amir, the privileged son of a wealthy Kabul merchant, witnesses the assault of his servant and closest friend Hassan without intervening, and spends the rest of his life carrying the guilt. Years later, in San Francisco, he receives a call from Pakistan offering him 'a way to be good again' — and returns to a Taliban-controlled Afghanistan he no longer recognizes. Hosseini's debut is unapologetically emotional and morally direct, exploring the ways that class, ethnicity, and cowardice shape betrayal. An international bestseller that gave many Western readers their first sustained encounter with Afghan culture and history." },

  { id: 47, rank: 47, title: "Her Body and Other Parties", author: "Carmen Maria Machado", year: 2017, genre: "Short Stories", coverId: 8545250,
    description: "Eight genre-bending stories at the intersection of the fantastical and the real, centering female experience, desire, and horror. A National Book Award finalist that announced Machado as one of the most exciting voices in American fiction.",
    longDescription: "Eight genre-bending stories work at the intersection of the fantastical and the mundane, centering female bodies, desire, and the specific textures of dread that women carry. The standout novella — a riff on an episode of 'Law & Order: SVU' extended to hundreds of pages — is one of the most formally audacious pieces of fiction in recent memory, investigating violence against women through the grammar of procedural television. Machado draws on Gothic literature, fairy tales, and horror to make visible what mainstream literary fiction often leaves in shadow: the threat that haunts female sexuality and autonomy. A National Book Award finalist." },

  { id: 48, rank: 48, title: "Stay True", author: "Hua Hsu", year: 2022, genre: "Memoir", coverId: 13195234,
    description: "A Pulitzer Prize-winning memoir about friendship, identity, and loss—specifically the devastating murder of the author's closest friend during their college years in 1990s California. A meditation on how we carry those we've lost.",
    longDescription: "Hua Hsu recounts his friendship with Ken Yoshida, formed during their years at UC Berkeley in the 1990s amid a world of zines, mixtapes, and the search for a politics of Asian-American identity — and Ken's senseless murder during a carjacking in 1998. The memoir is less about the violence than about what preceded it: the texture of a deep friendship, the way two people build a shared world from cultural references and private jokes. Hsu writes with a critic's precision and a mourner's ache about the ways we carry the dead within us. Winner of the Pulitzer Prize for Memoir." },

  { id: 49, rank: 49, title: "Freedom", author: "Jonathan Franzen", year: 2010, genre: "Literary Fiction", coverId: 8372428,
    description: "The Berglund family—Walter, Patty, and their son Joey—embody the freedoms and anxieties of early 21st-century American life. An ambitious, sprawling domestic novel about marriage, ambition, and ecological collapse.",
    longDescription: "Walter and Patty Berglund — outwardly model progressive citizens in a gentrifying St. Paul neighborhood — find their marriage and their values under pressure as their son Joey turns toward conservatism and Walter's lifelong friendship with rock musician Richard Katz grows complicated. Franzen's great subject is freedom itself: the American mythology of self-determination, and the ways that freedom, taken too literally, becomes a license to fail everyone around you. The novel was a cultural event on publication — named as 'Great American Novel' by Time magazine — and its achievement, if not its reception, has only grown with time." },

  { id: 50, rank: 50, title: "The Night Circus", author: "Erin Morgenstern", year: 2011, genre: "Fantasy", coverId: 8773134,
    description: "A mysterious black-and-white circus appears without warning, and within it two young magicians—bound to compete against each other—fall in love. A lushly imagined, enchanting debut rich with atmosphere and wonder.",
    longDescription: "The Cirque des Rêves appears without announcement, open only at night, entirely in black and white — and within its tents two young magicians, Celia and Marco, have been bound since childhood to compete in a contest whose rules neither fully understands. Morgenstern constructs the circus tent by tent in a prose style of extraordinary sensory richness, and the love story that develops between the competitors is genuinely moving. The novel prioritizes atmosphere and enchantment over plot mechanics, which is either its great pleasure or its central frustration depending on the reader. A global bestseller that found a devoted audience among readers who wanted to live inside its world." },

  { id: 51, rank: 51, title: "The Lovely Bones", author: "Alice Sebold", year: 2002, genre: "Literary Fiction", coverId: 6413803,
    description: "Fourteen-year-old Susie Salmon narrates from heaven as she watches her family and friends cope with her rape and murder, and her killer remains at large. A powerful, original debut that became a worldwide phenomenon.",
    longDescription: "Susie Salmon narrates from her personal heaven as she watches the world she left behind — her family fracturing under grief, her friends growing up, her killer living freely in the neighborhood — for the decade following her rape and murder at fourteen. Sebold, herself a rape survivor, brings unflinching honesty to the aftermath of violent crime, but the novel is also, unexpectedly, about joy: about what it means to love the world even from a great distance. The narrative device is both fantasy and therapeutic — a way of imagining the dead continuing to care about us. One of the bestselling debut novels of the 21st century." },

  { id: 52, rank: 52, title: "The Absolutely True Diary of a Part-Time Indian", author: "Sherman Alexie", year: 2007, genre: "Young Adult", coverId: 12366775,
    description: "Junior, a Native American teenager, leaves his school on the Spokane Indian Reservation to attend an all-white school off the reservation. A semi-autobiographical novel about poverty, race, and finding belonging.",
    longDescription: "Arnold Spirit Jr. — Junior — is a fourteen-year-old with a big brain and terrible luck, growing up on the Spokane Indian Reservation, who makes the radical decision to transfer to an all-white school twenty-two miles away. The novel, told through Junior's diary entries and illustrations, is partly autobiographical: Alexie made the same journey as a teenager. It is frank about the poverty and despair of reservation life without romanticizing it, and Junior's voice — funny, sharp, heartbroken — is one of the most distinctive in YA literature. Winner of the National Book Award for Young People's Literature." },

  { id: 53, rank: 53, title: "Bel Canto", author: "Ann Patchett", year: 2001, genre: "Literary Fiction", coverId: 5253806,
    description: "At a birthday party for a Japanese industrialist in South America, terrorists take the party hostage, and the weeks-long standoff creates unexpected bonds and beauty. A PEN/Faulkner Award-winning meditation on art and human connection.",
    longDescription: "At a lavish birthday party in an unnamed South American country, terrorists take dozens of guests hostage — including a world-famous opera singer performing for a Japanese industrialist. The months-long standoff that follows becomes, paradoxically, a space of unexpected grace: musicians play, languages are learned, and improbable loves form across the barrier between captors and captives. Patchett is interested in how art — specifically music — creates community where none should exist, and how beauty can persist in the most violent circumstances. Winner of the PEN/Faulkner Award and the Orange Prize." },

  { id: 54, rank: 54, title: "All the Light We Cannot See", author: "Anthony Doerr", year: 2014, genre: "Historical Fiction", coverId: 14559680,
    description: "A blind French girl and a German boy whose paths collide in occupied France during World War II. A Pulitzer Prize-winning novel of breathtaking beauty about the devastation of war and the redemptive power of human goodness.",
    longDescription: "Marie-Laure, a blind French girl who memorizes the streets of Paris through her father's scale models, and Werner, a German orphan with a gift for radio engineering who ends up in the Wehrmacht — their paths converge in the walled city of Saint-Malo during the final months of World War II. Doerr spent ten years on the novel and its prose has a jeweler's precision, building the world through specific sensory details that give the reader Marie-Laure's heightened experience of smell and sound and touch. The novel is both a war story and a meditation on the small acts of goodness that persist even in the darkest circumstances. Winner of the Pulitzer Prize." },

  { id: 55, rank: 55, title: "Homegoing", author: "Yaa Gyasi", year: 2016, genre: "Historical Fiction", coverId: 8081171,
    description: "Beginning in 18th-century Ghana with two half-sisters, one who marries a British slaver and one who is enslaved, the novel traces seven generations across both continents. A remarkable debut spanning three hundred years of history.",
    longDescription: "Beginning in 18th-century Ghana with two half-sisters — Effia, who marries a British slaver and lives in comfort above the slave dungeons of Cape Coast Castle, and Esi, who is imprisoned in those same dungeons and shipped to America — the novel traces seven generations of both family lines through chapters that move decade by decade toward the present. Gyasi wrote the book as her senior thesis at Stanford, then spent years expanding it, and the result has an economy and ambition that belies its length. Each chapter introduces a new protagonist while maintaining the thread of inherited trauma. A debut of remarkable assurance." },

  { id: 56, rank: 56, title: "The Overstory", author: "Richard Powers", year: 2018, genre: "Literary Fiction", coverId: 8758252,
    description: "Nine Americans, each with a unique relationship with trees, are drawn together in the fight to save the last virgin forests. A Pulitzer Prize-winning novel of epic scope about humanity's relationship with the natural world.",
    longDescription: "Nine Americans — each with a distinctive, formative relationship with a particular tree or forest — are drawn together over decades into the fight to save the last virgin timber in the Pacific Northwest. Powers structures the novel like a tree itself: roots, trunk, crown, seeds — each section opening outward from the individual stories into something that asks larger questions about time, ecology, and human self-destruction. The novel is essentially a work of ecological advocacy, but one that arrives at its arguments through deep characterization rather than polemic. Winner of the Pulitzer Prize, it has been credited with changing readers' relationships with the natural world." },

  { id: 57, rank: 57, title: "There There", author: "Tommy Orange", year: 2018, genre: "Literary Fiction", coverId: 8312263,
    description: "Twelve characters—all urban Native Americans in Oakland—converge on the Big Oakland Powwow, where a robbery is planned. A brilliant debut that forces a confrontation with the brutal realities facing Native Americans today.",
    longDescription: "Twelve characters — all urban Native Americans living in Oakland, each with a distinct history and relationship to Native identity — converge on the Big Oakland Powwow, where a group of young men have planned a robbery. The prologue, a furious and erudite account of the history of violence against Native Americans, is one of the most powerful pieces of writing in recent American fiction. Orange grew up in Oakland and writes the city and its Native community with the authority of the insider, insisting on the modernity and urban reality of a people still too often imagined as historical. A finalist for the Pulitzer Prize." },

  { id: 58, rank: 58, title: "Demon Copperhead", author: "Barbara Kingsolver", year: 2022, genre: "Literary Fiction", coverId: 13141227,
    description: "A modern retelling of David Copperfield set in the Appalachian hills of Virginia, following a boy born into the opioid epidemic who fights to rise above his circumstances. A Pulitzer Prize-winning novel of devastating empathy.",
    longDescription: "Damon Fields — Demon Copperhead — is born to a teenage single mother in the hill country of southwest Virginia, and the novel follows his life through the foster care system, high school football, and the opioid epidemic that kills so many people around him. Kingsolver resets Dickens's David Copperfield in rural Appalachia with meticulous fidelity to the source material, repurposing Victorian social critique as a vehicle for documenting the devastation wrought by OxyContin. Demon narrates his own story in a voice that is compelling, funny, and heartbreaking by turns. Winner of the Pulitzer Prize and the Women's Prize for Fiction." },

  { id: 59, rank: 59, title: "Trust", author: "Hernan Diaz", year: 2022, genre: "Literary Fiction", coverId: 12742248,
    description: "Four interlocking manuscripts present competing versions of a story about a mysterious Wall Street titan and his wife in early 20th-century New York. A Pulitzer Prize-winning puzzle about wealth, power, and who gets to tell our stories.",
    longDescription: "Four distinct manuscripts — a Gilded Age novel, a financier's memoir, a ghostwriter's diary, and a woman's fragmentary notes — present competing, mutually contradicting accounts of a mysterious Wall Street titan and his wife in early 20th-century New York. Diaz is interested in how wealth purchases narrative: who gets to tell the story of their own life, who gets erased, and what the gaps in official histories conceal. The puzzle structure is intellectually satisfying, but it is the final section — the wife's own voice emerging after a century of silence — that gives the novel its emotional core. Winner of the Pulitzer Prize." },

  { id: 60, rank: 60, title: "Piranesi", author: "Susanna Clarke", year: 2020, genre: "Fantasy", coverId: 10226290,
    description: "A man lives in a vast, labyrinthine house filled with statues and tidal halls, tending to its mysteries and those of the only other person there. A bewitching, dreamlike mystery about identity and the nature of reality.",
    longDescription: "Piranesi lives in a vast, labyrinthine House whose lower halls flood with tides, whose walls are lined with thousands of mysterious statues, and whose halls seem to extend infinitely in every direction. He tends the House faithfully, cataloguing its wonders in meticulous journals, and meets twice a week with the only other person there — a man he calls The Other. Clarke's second novel, published fifteen years after 'Jonathan Strange,' is entirely different in scale and mood: intimate, dreamlike, and constructed as a mystery that the reader solves alongside its amnesiac narrator. Winner of the Women's Prize for Fiction." },

  { id: 61, rank: 61, title: "On Earth We're Briefly Gorgeous", author: "Ocean Vuong", year: 2019, genre: "Literary Fiction", coverId: 10030425,
    description: "A letter from a son to his illiterate mother explores his Vietnamese-American family's history of trauma, addiction, and the beauty found amid devastation. A lyrical debut novel from one of America's most celebrated poets.",
    longDescription: "Written as a letter from a son called Little Dog to his illiterate Vietnamese-American mother, the novel explores three generations of trauma — war, displacement, addiction, and poverty — alongside the beauty that exists inside all of it. Vuong, who is primarily a poet, brings an extraordinary density of language to the novel form, and each page has the compression and weight of verse. The novel is centrally about the impossibility and necessity of telling one's own story to the person who most shaped it. A debut of stunning originality from one of the most acclaimed poets of his generation." },

  { id: 62, rank: 62, title: "The Vanishing Half", author: "Brit Bennett", year: 2020, genre: "Literary Fiction", coverId: 10095692,
    description: "Twin sisters from a small Black community in the Deep South run away at sixteen, and years later one sister is living as a white woman while the other has returned home. A sweeping generational saga about identity and race.",
    longDescription: "The Vignes twin sisters grow up in Mallard, a tiny Louisiana town where light-skinned Black residents have intermarried for generations, and run away together at sixteen. Years later Stella is living as a white woman in California, while Desiree has returned to Mallard with her dark-skinned daughter. Bennett constructs a decades-spanning story of passing, identity, and the legacies parents pass to children, told across two generations. The novel is interested less in the tragedy of 'passing' than in the enormous range of identities people construct and maintain — and the cost of the ones we cannot change. A #1 New York Times bestseller." },

  { id: 63, rank: 63, title: "Klara and the Sun", author: "Kazuo Ishiguro", year: 2021, genre: "Science Fiction", coverId: 10648686,
    description: "An artificial friend, or AF, observes the world from a shop window and eventually comes to live with a teenager named Josie, watching carefully and learning. A moving, quietly devastating exploration of love, sacrifice, and what it means to be human.",
    longDescription: "Klara is an Artificial Friend — a sophisticated android designed to be a companion to lonely children — who observes the world from her shop window with intense, careful attention, worshipping the Sun as the source of all her power and goodness. When she goes home with a teenage girl named Josie, she devotes herself completely to Josie's wellbeing in ways that raise profound questions about the nature of love and sacrifice. Ishiguro narrates through Klara's limited but earnest perspective, using her incomplete understanding of the world she inhabits to highlight what we take for granted in our own. The Nobel laureate's most recent novel." },

  { id: 64, rank: 64, title: "Tomorrow, and Tomorrow, and Tomorrow", author: "Gabrielle Zevin", year: 2022, genre: "Literary Fiction", coverId: 12859975,
    description: "Sam and Sadie—not lovers but soul mates of a different kind—collaborate as video game designers over thirty years, their partnership shaped by creative genius and personal tragedy. A dazzling novel about art, ambition, and connection.",
    longDescription: "Sam Masur and Sadie Green meet as children in a hospital and reconnect years later to become video game collaborators, spending three decades building games and navigating a creative partnership that is the most important relationship of both their lives — loving but not romantic, tender but sometimes brutal. Zevin uses video games as a serious artistic medium, constructing games that comment on the novel's own themes of agency, mortality, and the desire for control. The book is also a remarkably precise portrait of the tech and gaming world, from 1990s arcade games to the industry's current complexity. A bestseller that found an enormous readership across age groups." },

  { id: 65, rank: 65, title: "Lessons in Chemistry", author: "Bonnie Garmus", year: 2022, genre: "Literary Fiction", coverId: 12725772,
    description: "In early 1960s California, a female chemist becomes the unlikely star of a TV cooking show, teaching millions of housewives that their lives are their own experiments. A witty, feminist triumph.",
    longDescription: "Elizabeth Zott is a research chemist in 1960s California who cannot get a fair hearing in the male-dominated scientific world, and ends up — through a series of accidents and injustices — hosting a cooking show called 'Supper at Six.' Rather than dumb down her approach, she teaches her audience of housewives to cook using chemistry, inadvertently igniting a feminist consciousness across the country. Garmus's comedy is sharp and her anger is real, but the novel is also a warm celebration of female competence and solidarity. A slow-building bestseller that became a cultural phenomenon and a popular Apple TV+ series." },

  { id: 66, rank: 66, title: "A Gentleman in Moscow", author: "Amor Towles", year: 2016, genre: "Historical Fiction", coverId: 11326818,
    description: "Count Alexander Rostov is sentenced to house arrest in Moscow's Metropol Hotel, and the novel follows his life across thirty years. An elegantly written celebration of culture, friendship, and human dignity under Soviet rule.",
    longDescription: "Count Alexander Rostov is sentenced by a Bolshevik tribunal to spend the rest of his life under house arrest in the Metropol Hotel in Moscow, and the novel follows his life across the next thirty years — from the 1920s through Khrushchev's era — as he builds an entire world within the hotel's walls. Towles writes in an elegant, epigrammatic style that mirrors Rostov's aristocratic sensibility, and the novel is a deliberate celebration of the pleasures that culture, friendship, and refinement can sustain even under oppression. It is less interested in the horror of Stalinism than in the human capacity for grace within constraint. A global bestseller." },

  { id: 67, rank: 67, title: "Less", author: "Andrew Sean Greer", year: 2017, genre: "Literary Fiction", coverId: 8596367,
    description: "A failing novelist flees a difficult invitation by accepting every literary invitation around the world, embarking on a year of mishaps in a dozen countries. A Pulitzer Prize-winning comedy of remarkable warmth and wit.",
    longDescription: "Arthur Less, a middling American novelist turning fifty, flees the wedding of his ex-boyfriend by accepting every literary invitation that has piled up on his desk — a reading in New York, a conference in Mexico, a residency in Berlin, a prize in Italy, a cooking class in Morocco, a safari in South Africa — setting off a year of mishaps, embarrassments, and unexpected self-discovery. Greer writes about being gay, aging, and artistic mediocrity with warmth and wit, never letting the comedy become cruel. The novel is ultimately a love story, but one that arrives at its subject from a very roundabout direction. Winner of the Pulitzer Prize." },

  { id: 68, rank: 68, title: "Bring Up the Bodies", author: "Hilary Mantel", year: 2012, genre: "Historical Fiction", coverId: 10236749,
    description: "The second of Mantel's Wolf Hall trilogy follows Thomas Cromwell as he navigates the fall of Anne Boleyn at Henry VIII's court. A Booker Prize-winning novel of cold political maneuvering rendered with extraordinary psychological depth.",
    longDescription: "The second novel in Mantel's Wolf Hall trilogy follows Thomas Cromwell as Henry VIII tires of Anne Boleyn and Cromwell must build the case for her execution — a task that requires the destruction of five men along the way. Where 'Wolf Hall' is expansive and exploratory, 'Bring Up the Bodies' is tighter and darker: Cromwell is older, more powerful, and increasingly willing to use his power without scruple. Mantel renders the machinery of state violence with extraordinary precision, making us complicit in Cromwell's cold calculations even as we watch him destroy people he once liked. Winner of a second Man Booker Prize." },

  { id: 69, rank: 69, title: "Outline", author: "Rachel Cusk", year: 2014, genre: "Literary Fiction", coverId: 9079084,
    description: "A writer teaching a summer fiction course in Athens conducts a series of conversations with the people she meets, through which her own identity is gradually revealed. The first of Cusk's dazzling Outline trilogy, a reinvention of the novel form.",
    longDescription: "A British writer — never named, recently divorced — travels to Athens to teach a summer creative writing course, and the novel consists entirely of her conversations: with the man on the plane, her students, her hosts, a former lover. She says almost nothing about herself, but her identity is gradually outlined through what she elicits from others and what she chooses to relay. Cusk invented this form after her divorce memoir was savaged, and it represents a radical rethinking of what a novel can do — replacing plot and psychology with a kind of philosophical interview. The first in a trilogy that many critics regard as the most significant formal innovation in contemporary fiction." },

  { id: 70, rank: 70, title: "The Song of Achilles", author: "Madeline Miller", year: 2011, genre: "Fantasy", coverId: 7098465,
    description: "A retelling of the Iliad from the perspective of Patroclus, Achilles's devoted companion, chronicling their friendship and love from boyhood to the fields of Troy. An Orange Prize-winning reimagining of the ancient world.",
    longDescription: "Patroclus — the ungifted, exiled prince who becomes the companion of the divine, perfect Achilles — narrates the story of their life together from boyhood through training with Chiron the centaur to the long siege of Troy. Miller makes the relationship between Achilles and Patroclus explicitly romantic and writes their love with tenderness and conviction, filling in what Homer left ambiguous. The novel is at its best in the early sections, before the Trojan War begins, capturing a world of beauty and ease before the machinery of fate closes in. Winner of the Orange Prize for Fiction." },

  { id: 71, rank: 71, title: "Circe", author: "Madeline Miller", year: 2018, genre: "Fantasy", coverId: 8739376,
    description: "The daughter of the sun god Helios discovers her powers of witchcraft and must reckon with monsters, gods, and her own nature on her enchanted island. A feminist retelling of Greek myth that became a worldwide bestseller.",
    longDescription: "Circe, the daughter of the sun god Helios, is neither fully divine nor mortal — awkward, plain-voiced, ignored — until she discovers her power to transform creatures using herbs and incantation. Exiled to the island of Aeaea, she encounters a parade of mythological figures: Odysseus, Daedalus, the Minotaur, Medea — and must eventually reckon with what she wants her long immortal life to be. Miller's great achievement is making Circe's inner life fully credible, turning a figure who exists in Homer only to serve Odysseus into a woman whose choices feel genuinely consequential. A global bestseller that reached an audience far beyond the literary fiction world." },

  { id: 72, rank: 72, title: "The Magicians", author: "Lev Grossman", year: 2009, genre: "Fantasy", coverId: 6294573,
    description: "Quentin Coldwater is admitted to a secret college for magicians and discovers that a beloved fantasy world from his childhood books is real—and dangerous. A dark, sophisticated deconstruction of the fantasy genre.",
    longDescription: "Quentin Coldwater, a brilliant, depressive teenager from Brooklyn, is admitted to Brakebills — a secret upstate New York college for magicians — and discovers that magic is real, difficult, and not particularly healing. Later, he discovers that Fillory — the Narnia-like fantasy world from his favorite childhood books — is also real, and far darker than the books suggested. Grossman writes as someone who has read and loved fantasy all his life and wants to interrogate what it promises: that magic will cure unhappiness, that a better world awaits. The novel is a smart, melancholy response to both Harry Potter and Narnia. The first in a trilogy." },

  { id: 73, rank: 73, title: "Hag-Seed", author: "Margaret Atwood", year: 2016, genre: "Literary Fiction", coverId: 12511033,
    description: "A theater director who was fired in an act of betrayal finds himself teaching Shakespeare in a prison program, staging The Tempest as his act of revenge. Part of the Hogarth Shakespeare project—inventive and wickedly funny.",
    longDescription: "Felix Phillips, a theater director of brilliant, extravagant vision, is fired from his prestigious festival position by his ambitious assistant Tony in an act of betrayal. Twelve years later he is teaching Shakespeare to prisoners at a literacy program and hatches an elaborate plan: stage The Tempest with his incarcerated actors while the politicians responsible for his dismissal attend the performance. Atwood mirrors the play's themes of power, revenge, and forgiveness in Felix's scheme with playful precision, and her portrait of the prisoners discovering the resonance of Shakespeare's language with their own lives is the heart of the novel. Part of the Hogarth Shakespeare series." },

  { id: 74, rank: 74, title: "An Untamed State", author: "Roxane Gay", year: 2014, genre: "Literary Fiction", coverId: 7291143,
    description: "A Haitian-American woman is kidnapped while visiting Haiti and endures weeks of captivity and assault before her wealthy father agrees to pay the ransom. A fierce, unflinching exploration of trauma, privilege, and survival.",
    longDescription: "Mireille Duval Jameson — daughter of one of Haiti's wealthiest men, American-raised, married with an infant son — is kidnapped at the gates of her father's Port-au-Prince compound and held for thirteen days of brutality while her father refuses to pay the ransom on principle. Gay writes the violence without euphemism and the aftermath with equal unflinching attention: the novel's second half, as Mireille returns to her life and her marriage, is as disturbing as the abduction itself. The novel is deeply engaged with questions of class and colorism in Haiti, privilege's strange vulnerabilities, and the long arc of survival after trauma." },

  { id: 75, rank: 75, title: "The Buried Giant", author: "Kazuo Ishiguro", year: 2015, genre: "Fantasy", coverId: 12602978,
    description: "An elderly couple in post-Arthurian Britain journey across a land shrouded in collective forgetfulness to visit their son. A meditation on memory, violence, and whether nations—or couples—can sustain themselves on forgotten truth.",
    longDescription: "Axl and Beatrice, an elderly Briton couple in post-Arthurian England, set out to visit their son across a land shrouded in a strange collective amnesia — no one can remember the recent past. As they travel they encounter an aging Sir Gawain and a Saxon warrior, and the nature of the mist and its origins become gradually, disturbingly clear. Ishiguro uses the allegorical framework to ask whether individuals or nations can sustain love and peace on the foundation of forgotten atrocities, or whether that forgetting is itself a necessary lie. The novel divided critics — too slow for fantasy readers, too fantastical for literary readers — but rewards patience." },

  { id: 76, rank: 76, title: "The Power", author: "Naomi Alderman", year: 2016, genre: "Science Fiction", coverId: 7892681,
    description: "Teenage girls develop the power to release electrical jolts through their fingertips, and the consequences shift the entire balance of power between men and women globally. A speculative novel as provocative as The Handmaid's Tale.",
    longDescription: "When teenage girls around the world develop the ability to release painful and potentially lethal electrical jolts through their fingertips — and discover they can awaken the same ability in older women — the balance of power between men and women is systematically reversed across the globe. Alderman, who was mentored by Margaret Atwood, writes a dystopia that is not a simple inversion of patriarchy but a full investigation of how power shapes the people who hold it, regardless of gender. The novel is framed as a historical document written by a man in a matriarchal future, and the frame sharpens its critique. Winner of the Women's Prize for Fiction." },

  { id: 77, rank: 77, title: "The Testaments", author: "Margaret Atwood", year: 2019, genre: "Science Fiction", coverId: 12366815,
    description: "The Testaments returns to the totalitarian Republic of Gilead fifteen years after Offred's story ends, told by three women including an Aunt. The Booker Prize-winning sequel to Atwood's classic provides a satisfying—and chilling—expansion.",
    longDescription: "Set fifteen years after the end of 'The Handmaid's Tale,' the novel tells the story of Gilead's eventual unraveling through three first-person narrators: the formidable Aunt Lydia, a young woman raised in Gilead, and a Canadian girl with unexpected connections to the Republic. Where 'The Handmaid's Tale' was a claustrophobic portrait of oppression, 'The Testaments' is more expansive and plot-driven, revealing the architecture of Gilead's power and the seeds of its destruction. Atwood wrote the book partly in response to what she described as the unignorable political context of 2019. Joint winner of the Man Booker Prize." },

  { id: 78, rank: 78, title: "Fever Dream", author: "Samanta Schweblin", year: 2017, genre: "Horror", coverId: null,
    description: "In an Argentine hospital, a dying woman urgently tells her story to a boy named David as they try to locate the exact moment when the 'worm' entered her. A viscerally unsettling ecological horror novella.",
    longDescription: "Amanda lies dying in an Argentine hospital while a boy named David — the son of a woman she befriended on a rural holiday — sits by her bed, guiding her through a desperate reconstruction of recent events to find the exact moment when the 'worm' entered her. Schweblin builds her mystery through a dialogue structure of intense, urgent questions and answers, withholding the central horror while filling the narrative with the dread of contaminated water, sick cattle, and irresponsible agriculture. The novella is a formally radical ecological horror story — the pollution is literal and the metaphor is also literal — translated from Spanish by Megan McDowell. International Booker Prize shortlisted." },

  { id: 79, rank: 79, title: "Mexican Gothic", author: "Silvia Moreno-Garcia", year: 2020, genre: "Horror", coverId: 10239163,
    description: "In 1950s Mexico, glamorous socialite Noemí Taboada travels to a remote mansion to rescue her cousin from a mysterious illness—and discovers something deeply sinister within its walls. A hypnotic gothic horror with feminist undertones.",
    longDescription: "Glamorous, sharp-tongued socialite Noemí Taboada travels from Mexico City to a crumbling mansion in the mountains of Hidalgo to rescue her cousin Catalina from a mysterious illness and a possibly abusive marriage. The High Place is everything a Gothic house should be: damp, mold-smelling, presided over by a patriarch who believes in eugenics, and haunted in ways that become increasingly nightmarish. Moreno-Garcia layers 1950s Mexican class politics into her Gothic scaffolding, making race and power integral to the horror rather than incidental. A bestseller that revived interest in Latin American Gothic horror." },

  { id: 80, rank: 80, title: "The House of the Spirits", author: "Isabel Allende", year: 2001, genre: "Literary Fiction", coverId: null,
    description: "Four generations of the Trueba family in Chile experience love, violence, and political upheaval across the 20th century. A sweeping family saga in the magical realist tradition at its finest.",
    longDescription: "Four generations of the Trueba family — from the patriarch Esteban Trueba's youth in the early 20th century through the military coup that ends the novel — experience love, violence, clairvoyance, and political upheaval in an unnamed country clearly modeled on Chile. Allende, Gabriel García Márquez's cousin by marriage, writes in the tradition of magical realism with enormous warmth and political passion, centering the novel's moral vision in the women of the family. Though first published in 1982, it was reissued in the early 2000s and has remained continuously in print, a gateway to Latin American literature for generations of readers." },

  { id: 81, rank: 81, title: "Lincoln Highway", author: "Amor Towles", year: 2021, genre: "Literary Fiction", coverId: 10648601,
    description: "In 1954 America, eighteen-year-old Emmett Watson is released from a work farm and plans to drive west to start a new life—until two friends hijack his plans. An inventive, exhilarating adventure story organized around ten days.",
    longDescription: "Emmett Watson is released from a juvenile work farm in Nebraska in the summer of 1954 with a simple plan: collect his eight-year-old brother Billy and drive west to start over. But two friends from the work farm stow away in the trunk of the car and persuade Emmett to detour to New York City instead, setting off an adventure across 1950s America — an era of drive-ins, hitchhiking, and open possibility. Towles organizes the novel in ten chapters covering ten days, each narrated by a different character, and makes his 1950s America vibrant and specific. A love letter to the American road and the American adventure story." },

  { id: 82, rank: 82, title: "Bewilderment", author: "Richard Powers", year: 2021, genre: "Science Fiction", coverId: 11973940,
    description: "An astrobiologist attempts to save his neurodivergent son using an experimental treatment involving neural feedback therapy based on the brain patterns of the boy's dead mother. A moving meditation on fatherhood and environmental collapse.",
    longDescription: "Theo Byrne, an astrobiologist who searches for signs of life on other planets, struggles to protect his intense, neurodivergent nine-year-old son Robin from a world that wants to medicate him into compliance. When an experimental treatment — neural feedback therapy using the recorded brain patterns of Robin's dead mother — seems to transform the boy, Theo must weigh the costs. Powers writes science with genuine authority and compassion, and the father-son relationship at the novel's center is deeply felt. The book is also a passionate environmental novel about a world that is failing its most sensitive inhabitants. Shortlisted for the Booker Prize." },

  { id: 83, rank: 83, title: "The Dutch House", author: "Ann Patchett", year: 2019, genre: "Literary Fiction", coverId: 8788823,
    description: "A brother and sister are dispossessed of their magnificent Dutch House when their stepmother drives them out after their father's death, and the house haunts them for decades. A hypnotic novel about family, wealth, and forgiveness.",
    longDescription: "Danny and Maeve Conroy grow up in the Dutch House — a magnificent mansion on the outskirts of Philadelphia that their father bought impulsively during WWII — and are driven out by their cold, acquisitive stepmother after his death. For the next forty years they return obsessively to sit in a car outside the house, replaying their childhood and grieving the mother who left them. Patchett writes about sibling love and the power of childhood homes with extraordinary insight, and the Dutch House itself becomes a character — a repository of everything lost. Narrated by Danny looking back from middle age, it has the quality of a fairy tale made real." },

  { id: 84, rank: 84, title: "Anxious People", author: "Fredrik Backman", year: 2019, genre: "Literary Fiction", coverId: 10087939,
    description: "A failed bank robber takes a group of strangers hostage during an open house viewing, and the resulting police investigation and character study reveals ordinary human failures and kindnesses. A warmhearted, witty puzzle of a novel.",
    longDescription: "A failed bank robber — whose attempted robbery was derailed when the bank turned out to have no cash — accidentally takes a group of strangers hostage in an apartment open house on New Year's Eve, then disappears without a trace when police arrive. The novel unfolds through interviews with the hostages, gradually revealing how the strangers' lives intersect and what the day meant to each of them. Backman constructs an elaborate puzzle that is also a warm defense of ordinary human messiness and the small kindnesses that prevent despair. Funny and sad in equal measure, it became an international bestseller and a Netflix series." },

  { id: 85, rank: 85, title: "A Man Called Ove", author: "Fredrik Backman", year: 2012, genre: "Literary Fiction", coverId: null,
    description: "Ove is the curmudgeonly, suicidal widower next door—until a boisterous young family moves in and gradually draws him back into life. A funny, profoundly moving Swedish bestseller about love, loneliness, and belonging.",
    longDescription: "Ove is fifty-nine, recently widowed and recently fired, and is methodically planning his own death when a chaotic young family moves in next door and keeps needing his help with tasks he cannot refuse. Backman reveals Ove's inner life through flashbacks — his love for his late wife Sonja, his lifetime of principled stubbornness — and the comedy comes from the gap between his grumpiness and the depth of his feeling. The novel is sentimental but honestly so: it trusts the reader to feel without being manipulated. A Swedish publishing phenomenon that became an international bestseller and has been adapted twice into films." },

  { id: 86, rank: 86, title: "The Midnight Library", author: "Matt Haig", year: 2020, genre: "Literary Fiction", coverId: 10313767,
    description: "Nora Seed finds herself in a library between life and death that contains books representing every version of her life she could have lived. A life-affirming novel about regret, possibility, and the reasons to keep living.",
    longDescription: "Nora Seed, overwhelmed by the weight of her regrets, attempts suicide and finds herself in a library between life and death, tended by her childhood librarian. Every book on the shelves represents a version of her life as it could have been — if she had kept swimming competitively, if she had married her ex-fiancé, if she had moved to Australia with her brother — and she can try each one. Haig uses the premise as a vehicle for a direct, compassionate argument against the finality of despair, exploring what makes any particular life worth living. Published at the height of the pandemic, it became one of the bestselling books of 2020." },

  { id: 87, rank: 87, title: "The Seven Husbands of Evelyn Hugo", author: "Taylor Jenkins Reid", year: 2017, genre: "Literary Fiction", coverId: 8354226,
    description: "Hollywood icon Evelyn Hugo finally agrees to tell her story to an unknown journalist, revealing a life of ambition, heartbreak, and a great secret love. A compulsive, glittering novel about fame, sacrifice, and identity.",
    longDescription: "Evelyn Hugo, a fictitious Hollywood icon of the 1950s through 1980s — Cuban-American, impossibly beautiful, married seven times — finally agrees to tell her full story to an unknown journalist named Monique Grant, and her reasons for choosing Monique are the novel's central mystery. Reid constructs Evelyn's story with the pleasures of old Hollywood glamour and genuine emotional weight, centering a great love story that Evelyn kept hidden throughout her public life. The novel is about the price of fame, the compromises of ambition, and the loneliness of living inside a constructed identity. Grew from a modest success into a global phenomenon through social media." },

  { id: 88, rank: 88, title: "Beautiful Boy", author: "David Sheff", year: 2008, genre: "Memoir", coverId: 6609387,
    description: "A father chronicles his son Nic's devastating addiction to crystal methamphetamine and the family's desperate, exhausting efforts to help him recover. A heart-rending account of addiction and parental love.",
    longDescription: "David Sheff chronicles the years-long nightmare of his son Nic's addiction to crystal methamphetamine — from his son's brilliant early childhood through the first warning signs, the escalating crises, the rehab admissions and relapses, and the ongoing uncertainty of recovery. Sheff writes as a journalist reporting on his own family, bringing research about the neuroscience of addiction alongside the raw emotional experience of watching a beloved child be destroyed. The memoir is unusual in centering the parent's perspective rather than the addict's, and its account of enablement and helplessness is searingly honest. Adapted into a film starring Steve Carell and Timothée Chalamet." },

  { id: 89, rank: 89, title: "The Inheritance Games", author: "Jennifer Lynn Barnes", year: 2020, genre: "Young Adult", coverId: 10472357,
    description: "A teenage girl inherits the entire estate of a billionaire with no known connection to her, and must live with his four grandsons and solve his elaborate puzzles to discover why. An addictive YA mystery full of twists.",
    longDescription: "Avery Grambs, a scholarship student just trying to get through senior year, discovers that Tobias Hawthorne — one of the wealthiest men in America, whom she has never met — has left her his entire fortune, cutting out his four grandsons entirely. To inherit, she must live in Hawthorne House with the four brothers and untangle the elaborate puzzles the old man left behind. Barnes writes with propulsive energy and genuine skill at constructing mysteries, and the four Hawthorne brothers are each distinctively drawn. The first in a series that became one of the most-read YA franchises of recent years." },

  { id: 90, rank: 90, title: "Persepolis", author: "Marjane Satrapi", year: 2003, genre: "Memoir", coverId: 12648921,
    description: "A graphic memoir following the author's childhood in Iran during the Islamic Revolution and her subsequent years as an exile in Europe. A bold, funny, and heartbreaking account of growing up between two worlds.",
    longDescription: "Satrapi's graphic memoir follows her childhood in Tehran — the daughter of progressive, Marxist parents — through the Islamic Revolution and the Iran-Iraq war, and then her years as a teenager exiled to Vienna, where she was more Iranian than she wanted to be, and back in Iran as a young adult, where she was more Western than the regime could tolerate. The black-and-white drawings have a deceptive simplicity that makes the political events feel immediate and the personal moments deeply felt. Originally published in French in two volumes, it was adapted into an acclaimed animated film and remains one of the most-read graphic memoirs in the world." },

  { id: 91, rank: 91, title: "The Glass Castle", author: "Jeannette Walls", year: 2005, genre: "Memoir", coverId: 11517692,
    description: "The author recounts her unconventional, chaotic childhood with her eccentric, neglectful parents—a dreaming father and a free-spirited mother—who moved constantly across the American West. A riveting story of resilience and complicated love.",
    longDescription: "Jeannette Walls grew up perpetually moving across the American West and Southwest with her father Rex — a brilliant, alcoholic dreamer who always had plans for a glass castle he would someday build — and her artistic, free-spirited, frequently irresponsible mother. The memoir is remarkable for what it refuses to do: sentimentalize the parents into villains or the childhood into pure tragedy. Walls writes her parents with genuine love alongside clear-eyed assessment of the damage they did, and the result is one of the most nuanced accounts of growing up in dysfunction ever written. A #1 New York Times bestseller for years after publication." },

  { id: 92, rank: 92, title: "In the Woods", author: "Tana French", year: 2007, genre: "Literary Fiction", coverId: 1474730,
    description: "Dublin Murder Squad detective Rob Ryan investigates the murder of a twelve-year-old girl in the same woods where his childhood friends vanished decades ago. A riveting debut that announced French as one of crime fiction's finest writers.",
    longDescription: "Detective Rob Ryan of the Dublin Murder Squad volunteers to investigate the murder of a twelve-year-old girl found on an altar stone in Knocknaree — the same woods where he survived an incident as a child that killed two of his friends and that he cannot remember. French weaves together the present-day investigation and Rob's fragmented memory of the past with extraordinary skill, and the novel's climax is genuinely shocking not just in terms of plot but in what it reveals about its narrator's unreliability. The first of the Dublin Murder Squad novels, each of which follows a different detective, and widely considered one of the finest crime debuts of the century." },

  { id: 93, rank: 93, title: "The Girl with the Dragon Tattoo", author: "Stieg Larsson", year: 2005, genre: "Literary Fiction", coverId: null,
    description: "Journalist Mikael Blomkvist and hacker Lisbeth Salander investigate the disappearance of a wealthy patriarch's grandniece decades earlier. A hugely addictive Swedish thriller that redefined crime fiction worldwide.",
    longDescription: "Disgraced journalist Mikael Blomkvist is hired by an elderly industrialist to investigate the disappearance of his grandniece Harriet forty years earlier, while simultaneously he encounters the brilliant, traumatized computer hacker Lisbeth Salander, who becomes his most important partner. Larsson — who died of a heart attack the year after completing his Millennium trilogy — wrote books that were simultaneously populist thrillers and investigations of violence against women in Swedish society. Lisbeth Salander became one of the most iconic characters in contemporary fiction: utterly outside social norms, profoundly damaged, and fiercely herself. Published posthumously, the books sold over 100 million copies worldwide." },

  { id: 94, rank: 94, title: "The Committed", author: "Viet Thanh Nguyen", year: 2021, genre: "Literary Fiction", coverId: 10326406,
    description: "The nameless spy from The Sympathizer arrives in Paris, where he attempts to start a new life selling drugs while confronting the legacy of colonialism. A wildly ambitious sequel full of sharp comedy and political ferocity.",
    longDescription: "The nameless spy from 'The Sympathizer' arrives in Paris — the belly of the colonial beast — where he and his blood brother attempt to start a new life by working for a Vietnamese drug dealer, while the spy's dual consciousness keeps tearing apart whatever stability he builds. Nguyen writes the spy's internal monologue as a kind of ongoing philosophical debate about colonialism, identity, and the impossibility of decolonizing the mind, referencing Sartre, Fanon, and others directly. The comedy is blacker and the ambitions larger than in the first novel. A work that demands and rewards engagement with its intellectual density." },

  { id: 95, rank: 95, title: "2666", author: "Roberto Bolaño", year: 2004, genre: "Literary Fiction", coverId: 1047310,
    description: "Five interlocking narratives circle around a fictional Mexican city plagued by unsolved femicides, linked by a mysterious German author. A monumental, posthumously published masterwork of dark genius.",
    longDescription: "Five interlocking narratives — about literary critics, a reclusive German novelist, a philosophy professor, a Black American journalist covering a boxing match, and the hundreds of murdered women in the fictional city of Santa Teresa — circle around each other without ever quite converging, in a novel of overwhelming scope and dark intelligence. Bolaño, who died of liver disease in 2003, intended to publish the five parts separately; his family published them as one volume after his death. The central section, 'The Part About the Crimes,' is one of the most harrowing things in modern literature: a documentary catalogue of femicides that refuses to look away. One of the defining novels of the 21st century." },

  { id: 96, rank: 96, title: "The Lacuna", author: "Barbara Kingsolver", year: 2009, genre: "Historical Fiction", coverId: 6422680,
    description: "A young man born to a Mexican mother and American father moves between Mexico City—where he works for Diego Rivera and Trotsky—and the American South during WWII. A sweeping novel about art, history, and the stories we are allowed to tell.",
    longDescription: "Harrison Shepherd grows up between Mexico and America — his Mexican mother's lover, and then his employer, is Diego Rivera, in whose household Leon Trotsky also briefly lives — before moving to Asheville, North Carolina, where he becomes a successful novelist until McCarthyism destroys him. Kingsolver is interested in the lacunas: the gaps in the historical record, the stories that get suppressed, the way official narratives erase inconvenient truths. The novel moves between Mexico's radical art world of the 1930s and the anti-communist hysteria of 1940s and 1950s America with equal confidence. Winner of the Orange Prize." },

  { id: 97, rank: 97, title: "Crying in H Mart", author: "Michelle Zauner", year: 2021, genre: "Memoir", coverId: 10462708,
    description: "The musician Michelle Zauner chronicles losing her Korean mother to cancer and explores her relationship with Korean identity through food. A wrenching, beautiful memoir that became an instant classic.",
    longDescription: "Michelle Zauner — the Korean-American musician behind Japanese Breakfast — chronicles the death of her Korean mother from cancer and her subsequent grief, which manifests partly as an obsessive return to Korean food and cooking as a way of staying connected to her mother's culture. The memoir is organized around food: the H Mart of the title is the Korean grocery chain where Zauner goes to grieve and to cook, and her descriptions of Korean cuisine are both lovingly precise and deeply elegiac. The book is also about the particular dynamics of a demanding Korean mother and the daughter who loved and resented her. Expanded from an acclaimed New Yorker essay." },

  { id: 98, rank: 98, title: "Matrix", author: "Lauren Groff", year: 2021, genre: "Historical Fiction", coverId: 10831680,
    description: "A young woman—perhaps Marie de France—is sent to rule a struggling abbey in 12th-century England and transforms it through visionary leadership. A fierce, intensely lyrical meditation on faith, power, and female ambition.",
    longDescription: "A seventeen-year-old woman — perhaps Marie de France, the 12th-century poet — is sent from the French court to take charge of a poverty-stricken English abbey and transforms it through sheer force of will and vision into a thriving center of female power. Groff writes in a rushing, incantatory prose that is unlike almost anything else in contemporary fiction, and her Marie is simultaneously a medieval abbess and a fully modern consciousness — ambitious, erotic, visionary, and ruthless. The novel is about what women can build within the constraints imposed on them, and how faith can be both genuine and a vehicle for power. Longlisted for the Booker Prize." },

  { id: 99, rank: 99, title: "The Covenant of Water", author: "Abraham Verghese", year: 2023, genre: "Historical Fiction", coverId: 13190092,
    description: "Spanning three generations of a family in South India from 1900 to 1977, a family is marked by a mysterious condition—one member in each generation dies by drowning. A magnificent novel of medicine, faith, and the bonds of family.",
    longDescription: "Beginning in 1900 in South India, when a twelve-year-old girl is married into a family marked by a mysterious hereditary condition — one member in each generation dies by water — the novel follows three generations across the region's enormous transformations: colonialism, Independence, the Emergency. Verghese, a physician, writes the practice of medicine across the decades with deep knowledge and genuine reverence, and his portrait of the South Indian landscape is extraordinarily vivid. The novel is long and deliberate, accumulating detail in the manner of the great Victorian novels it consciously echoes. Verghese's most ambitious work, and his most celebrated." },

  { id: 100, rank: 100, title: "Intermezzo", author: "Sally Rooney", year: 2024, genre: "Literary Fiction", coverId: 14836043,
    description: "Two grieving brothers—one a top chess player, one a lawyer—navigate love and loss after their father's death. Rooney's most emotionally mature novel to date, a meditation on grief and human connection.",
    longDescription: "Peter Kowalski, a successful Dublin lawyer with two complicated relationships on the go, and his younger brother Ivan, a chess prodigy with an unexpected new love, are united only by grief after their father's death. Rooney writes the two brothers alternately, in styles as different as their personalities, and the novel is interested in how grief strips away the performances we maintain and forces us to be known. More formally experimental than her previous novels — the prose shifts register between characters with less conventional punctuation — it is also more emotionally generous. Widely seen as Rooney's most mature novel to date." },
];
